+func TestTranscriptWriter_InterleavedSeqNumbers(t *testing.T) {
+	dir := t.TempDir()
+	path := filepath.Join(dir, "transcript.jsonl")
+
+	w, err := NewTranscriptWriter(path, TranscriptHeader{
+		SessionID: "sess-interleave",
